use soroban_sdk::{contract, contractimpl, Address, Env, Bytes, Symbol};

#[contractimpl]
impl AdminContract {
    // VULNERABLE: set_admin without auth guard
    pub fn set_admin(env: Env, new_admin: Address) {
        env.storage().instance().set(&Symbol::new(&env, "admin"), &new_admin);
    }

    // VULNERABLE: withdraw without auth guard
    pub fn withdraw(env: Env, amount: i128) {
        env.storage().instance().set(&Symbol::new(&env, "balance"), &0i128);
    }

    // VULNERABLE: pause without auth
    pub fn pause(env: Env) {
        env.storage().instance().set(&Symbol::new(&env, "paused"), &true);
    }

    // VULNERABLE: burn without auth guard
    pub fn burn(env: Env, from: Address, amount: i128) {
        env.storage().instance().set(&from, &amount);
    }

    // SAFE: regular function (not a privileged pattern, not flagged)
    pub fn get_balance(env: Env, address: Address) -> i128 {
        env.storage().instance().get(&address).unwrap_or(0)
    }
}
